15	  items: Item[];
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Policy {
27	  items: Item[];
28	  insuranceSum: number;
29	  remainingCap: number;
30	}
