50	const BASE_PREMIUMS: Record<string, number> = {
51	  sword: 100,
52	  amulet: 60,
53	  staff: 80,
54	  potion: 40,
55	  rune: 25,
56	  moonstone: 25,
57	};
58	
59	const INSURANCE_VALUES: Record<string, number> = {
60	  sword: 1000,
61	  amulet: 600,
62	  staff: 800,
63	  potion: 400,
64	  rune: 250,
65	  moonstone: 250,
66	};
67	
68	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
69	const DEDUCTIBLE = 100;
70	const PROCESSING_FEE = 5;
71	const BLOCK_SIZE = 3;
72	const BLOCK_PRICE = 60;
73	const CURSED_SURCHARGE_RATE = 0.5;
74	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
75	const HIGH_ENCHANTMENT_THRESHOLD = 5;
76	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
77	const LOYALTY_DISCOUNT_RATE = 0.2;
78	const LOYALTY_YEARS_THRESHOLD = 2;
79	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
80	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
81	const CLAIM_HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
82	
83	const calculateQuotePremium = (items: Item[], customer: { yearsWithMHPCO: number }, quoteIndex: number): number => {
84	  let basePremium = 0;
85	  let itemSurcharges = 0;
86	  const componentCounts: Record<string, number> = {};
87	
88	  for (const item of items) {
89	    if (!(item.type in BASE_PREMIUMS)) {
90	      throw new Error(`Unknown item type: ${item.type}`);
91	    }
92	    if (COMPONENT_TYPES.has(item.type)) {
93	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
94	    } else {
95	      const itemBasePremium = BASE_PREMIUMS[item.type];
96	      basePremium += itemBasePremium;
97	      if (item.cursed) {
98	        itemSurcharges += itemBasePremium * CURSED_SURCHARGE_RATE;
99	      }
100	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
101	        itemSurcharges += itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
102	      }
103	    }
104	  }
105	
106	  for (const [type, count] of Object.entries(componentCounts)) {
107	    basePremium += count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUMS[type];
108	  }
109	
110	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
111	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
112	  const followUpDiscount = quoteIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
113	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
114	};
115	
116	const CAP_MULTIPLIER = 2;
117	
118	const calculateInsuranceSum = (items: Item[]): number =>
119	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
120	
121	const calculateClaimPayout = (step: ClaimStep, policy: Policy): ClaimResult => {
122	  const damageCounts: Record<string, number> = {};
123	  for (const damage of step.incident.damages) {
124	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] || 0) + 1;
125	  }
126	  for (const [itemType, count] of Object.entries(damageCounts)) {
127	    const policyCount = policy.items.filter((i) => i.type === itemType).length;
128	    if (count > policyCount) {
129	      throw new Error(`More damage entries for ${itemType} than policy covers`);
130	    }
131	  }
132	  let totalPayout = 0;
133	  for (const damage of step.incident.damages) {
134	    const policyItem = policy.items.find((i) => i.type === damage.itemType);
135	    if (!policyItem) {
136	      throw new Error(`Claim references item type not in policy: ${damage.itemType}`);
137	    }
138	    if (damage.amount < 0) {
139	      throw new Error(`Negative damage amount: ${damage.amount}`);
140	    }
141	    let reimbursement = damage.amount;
142	    if (policyItem.enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD) {
143	      reimbursement = damage.amount * CLAIM_HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
144	    }
145	    totalPayout += Math.max(0, reimbursement - DEDUCTIBLE);
146	  }
147	  totalPayout = Math.floor(totalPayout);
148	  totalPayout = Math.min(totalPayout, policy.remainingCap);
149	  policy.remainingCap -= totalPayout;
150	  return { payout: totalPayout, remainingCap: policy.remainingCap };
151	};
152	
153	export const processScenario = (scenario: Scenario): ScenarioResult => {
154	  let quoteCount = 0;
155	  const policies: Policy[] = [];
156	  const results = scenario.steps.map((step, index) => {
157	    if (step.op === "quote") {
158	      const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount);
159	      const insuranceSum = calculateInsuranceSum(step.items);
160	      policies[index] = { items: step.items, insuranceSum, remainingCap: insuranceSum * CAP_MULTIPLIER };
161	      quoteCount++;
162	      return { premium };
163	    }
164	    return calculateClaimPayout(step, policies[step.policy]);
165	  });
166	  return { results };
167	};
